import React from 'react';
import { z } from 'zod';
import { SlideIn } from '../slide-in/SlideIn';
import { FadeIn } from '../fade-in/FadeIn';
import { Underline } from '../underline/Underline';
import { useVideoConfig } from 'remotion';
import { PlacementBox, resolvePlacement, resolveSize } from '../../../lib/canvas';
import { lowerThirdSchema } from './schema';

export { lowerThirdSchema };
export type LowerThirdProps = z.infer<typeof lowerThirdSchema>;

/**
 * Broadcast-style name + role bar that slides in from a corner with a single
 * accent underline. A restrained scene block composed from `SlideIn`,
 * `FadeIn`, and `Underline` — no chrome, no glow, one earned accent.
 *
 * The slide direction and inner alignment derive from `placement` — a bar
 * placed on the right slides in from the right and aligns flush right.
 *
 * @example
 * <LowerThird name="Rodrigo" role="CEO, Onda" placement="bottom-right" />
 */
export const LowerThird: React.FC<LowerThirdProps> = ({
  name,
  role,
  placement,
  delay,
  accent,
  color,
  roleColor,
  accentColor,
  fontSize,
  nameSize,
  nameFontWeight,
  nameLetterSpacing,
  nameLineHeight,
  roleFontSize,
  roleSize,
  roleFontWeight,
  roleLetterSpacing,
  roleLineHeight,
  fontFamily,
}) => {
  const { width, height } = useVideoConfig();
  const resolvedNameFontSize = nameSize ? resolveSize(nameSize, { width, height }) : fontSize;
  const resolvedRoleFontSize = roleSize ? resolveSize(roleSize, { width, height }) : roleFontSize;
  // Derive the visual side from the resolved placement's x coordinate. A bar
  // on the left half slides in from the left and aligns flush-left; on the
  // right half it mirrors. Anchor-flush via PlacementBox handles the rest.
  const isLeft = resolvePlacement(placement).x < 0.5;

  // Choreography offsets — frames *after* the name's delay.
  // Role follows the name by 4 frames (the canonical Onda stagger).
  // Underline lands last at +8 frames so the eye reads name -> role -> accent.
  const ROLE_OFFSET = 4;
  const UNDERLINE_OFFSET = 8;

  // SlideIn direction matches the side the bar sits on — subtle horizontal
  // travel reinforces which corner the bar belongs to.
  const slideDirection = isLeft ? 'left' : 'right';

  return (
    <PlacementBox placement={placement}>
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: isLeft ? 'flex-start' : 'flex-end',
          gap: 4,
          fontFamily,
        }}
      >
        {/* Name — slides in from the side. Uses the primitive's own spring. */}
        <SlideIn kind="slide-in"
          text={name}
          delay={delay}
          direction={slideDirection}
          color={color}
          fontSize={resolvedNameFontSize}
          fontFamily={fontFamily}
          fontWeight={nameFontWeight}
          letterSpacing={nameLetterSpacing}
          lineHeight={nameLineHeight}
          distance={16}
          duration={18}
        />

        {/* Role — fades in 4 frames after the name. */}
        <FadeIn kind="fade-in"
          text={role}
          delay={delay + ROLE_OFFSET}
          color={roleColor}
          fontSize={resolvedRoleFontSize}
          fontFamily={fontFamily}
          fontWeight={roleFontWeight}
          letterSpacing={roleLetterSpacing}
          lineHeight={roleLineHeight}
          duration={18}
        />

        {/* Accent underline — appears last, only when accent === true.
            The Underline primitive draws its own line; we pass an empty
            string for text so only the accent rule is visible (the name
            above already owns the typography). */}
        {accent ? (
          <div
            style={{
              marginTop: 8,
              alignSelf: isLeft ? 'flex-start' : 'flex-end',
            }}
          >
            <Underline kind="underline"
              text=""
              delay={delay + UNDERLINE_OFFSET}
              color={color}
              accentColor={accentColor}
              fontSize={resolvedNameFontSize}
              fontFamily={fontFamily}
              duration={1}
              lineDelay={0}
              lineThickness={3}
              lineOffset={0}
              lineDuration={10}
            />
          </div>
        ) : null}
      </div>
    </PlacementBox>
  );
};

export default LowerThird;

import { z } from 'zod';
import { placementSchema, sizeRoleSchema } from '../../../lib/canvas-schemas';

/** Zod schema for `LowerThird` props. */
export const lowerThirdSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted (`schema.parse({})` works as before). Lets consumers build `z.discriminatedUnion('kind', [...])` directly over onda schemas. */
  kind: z.literal('lower-third').default('lower-third'),
  /** The person's name. */
  name: z.string().default('Rodrigo'),
  /** The person's role / title. */
  role: z.string().default('CEO, Onda'),
  /** Where on the canvas the bar sits. Region (`'bottom-left'`, `'bottom-right'`, ...) or `{ x, y, anchor }` in 0..1 canvas fractions. Defaults to `'bottom-left'`. */
  placement: placementSchema.optional().default('bottom-left'),
  /** Frames before the name slides in. */
  delay: z.number().int().min(0).default(0),
  /** Show the accent underline beneath the name. */
  accent: z.boolean().default(true),
  /** Name color. Defaults to `--onda-text`. */
  color: z.string().default('var(--onda-text, #F2F2F4)'),
  /** Role color. Defaults to `--onda-dim`. */
  roleColor: z.string().default('var(--onda-dim, #8E8E98)'),
  /** Underline color. Defaults to `--onda-accent`. */
  accentColor: z.string().default('var(--onda-accent, #D96B82)'),
  /** Name font size in px. Wins over `nameSize` if both are passed. */
  fontSize: z.number().default(48),
  /** Semantic role for the name — resolves to canvas-aware pixels. `fontSize` wins when both are passed. */
  nameSize: sizeRoleSchema.optional(),
  /** Font weight for the name. */
  nameFontWeight: z.number().optional(),
  /** CSS letter-spacing for the name (e.g. `'-0.02em'`). */
  nameLetterSpacing: z.string().optional(),
  /** Unitless line height for the name. */
  nameLineHeight: z.number().optional(),
  /** Role font size in px. Wins over `roleSize` if both are passed. */
  roleFontSize: z.number().default(22),
  /** Semantic role for the role line — resolves to canvas-aware pixels. `roleFontSize` wins when both are passed. */
  roleSize: sizeRoleSchema.optional(),
  /** Font weight for the role. */
  roleFontWeight: z.number().optional(),
  /** CSS letter-spacing for the role (e.g. `'0.06em'`). */
  roleLetterSpacing: z.string().optional(),
  /** Unitless line height for the role. */
  roleLineHeight: z.number().optional(),
  /** Onda display font. */
  fontFamily: z.string().default('var(--onda-font-display, "Clash Display", sans-serif)'),
});

/** Inferred props for `LowerThird`. */
export type LowerThirdProps = z.infer<typeof lowerThirdSchema>;
